#include<bits/stdc++.h>
using namespace std;

int main() {
	long long a,b;
	cin>>a>>b;
	if(a==1) {
		cout<<1;
		return 0;
	}
	if(b==1) {
		cout<<a;
		return 0;
	}
	long long c=1;
	for(int i=1; i<=b; i++) {
		c*=a;
		if(c>1e9) {
			cout<<-1;
			return 0;
		}
	}
	cout<<c;
	return 0;
}
